--- lib/fs/basicfs_lstat_windows.go
+++ lib/fs/basicfs_lstat_windows.go
@@ -143,7 +143,7 @@

 func (f *BasicFilesystem) underlyingLstat(name string) (os.FileInfo, error) {
        var fi, err = os.Lstat(name)

-       // There are cases where files are tagged as symlink, but they end up being
+       // There are cases where files are tagged as symlink or junction, but they end up being
        // something else. Make sure we properly handle those types.
        if err == nil {
                // NTFS directory junctions can be treated as ordinary directories,
@@ -155,7 +155,7 @@
                        return &dirJunctFileInfo{fi}, nil
                }
        }
-
+       // If the file is not a junction but has a reparse tag, try to read it
        if err == nil && f.junctionsAsDirs {
                reparseTag, reparseErr := readReparseTag(name)
                if reparseErr == nil && isDirectoryJunction(reparseTag) {
                        return &dirJunctFileInfo{fi}, nil
                }
        }

        return fi, err
 }
